import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, RouterLinkActive, RouterOutlet } from '@angular/router';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  path: string;
  icon: string;
  managerOnly?: boolean;
}

@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive, RouterOutlet],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent {
  drawerOpen = signal(false);

  private readonly allNav: NavItem[] = [
    { label: 'Dashboard', path: '/dashboard', icon: '📊', managerOnly: true },
    { label: 'Units', path: '/units', icon: '🏢', managerOnly: true },
    { label: 'Leases', path: '/leases', icon: '📄', managerOnly: true },
    { label: 'Tenants', path: '/tenants', icon: '👥', managerOnly: true },
    { label: 'Post Charges', path: '/post-charges', icon: '💸', managerOnly: true },
    { label: 'Delinquency', path: '/delinquency', icon: '⚠️', managerOnly: true },
    { label: 'Settings', path: '/admin/settings', icon: '⚙️', managerOnly: true },
    { label: 'My Lease', path: '/my-lease', icon: '🏠' },
    { label: 'Statement', path: '/my-lease/statement', icon: '🧾' },
  ];

  readonly nav = computed<NavItem[]>(() => {
    const isManager = this.auth.isManager();
    return this.allNav.filter((n) => {
      if (n.managerOnly) return isManager;
      // tenant-only items shown to tenants
      return !isManager;
    });
  });

  // Bottom-tab nav shows at most 5 primary items on mobile.
  readonly bottomNav = computed<NavItem[]>(() => this.nav().slice(0, 5));

  readonly userName = computed(() => this.auth.user()?.name || this.auth.user()?.email || 'Account');
  readonly roleLabel = computed(() => (this.auth.isManager() ? 'Manager' : 'Tenant'));

  constructor(public auth: AuthService) {}

  toggleDrawer(): void {
    this.drawerOpen.update((v) => !v);
  }

  closeDrawer(): void {
    this.drawerOpen.set(false);
  }

  logout(): void {
    this.auth.logout();
  }
}
